const themeFreq = (() => {
  const c={};
  meetingsData.forEach(m => m.themes.forEach(t => { c[t]=(c[t]||0)+1; }));
  return Object.entries(c).sort((a,b)=>b[1]-a[1]).map(([name,count])=>({name,count}));
})();

