const cityGeo = (() => {
  const cities = {};
  meetingsData.forEach(m => {
    if (!cities[m.place]) cities[m.place] = { place:m.place, host:m.host, count:0 };
    cities[m.place].count++;
  });
  return Object.values(cities).map(c => ({
    ...c,
    pctX: cityPositions[c.place]?.x || 50,
    pctY: cityPositions[c.place]?.y || 50,
  })).sort((a,b) => a.count - b.count);
})();

