function StatusBadge({ status }) {
  const a = status === "Achieved";
  return (
    <span className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-[10px] font-semibold tracking-wide border ${
      a ? "bg-emerald-50 text-emerald-700 border-emerald-200" : "bg-amber-50 text-amber-700 border-amber-200"}`}>
      {a ? <CheckCircle2 size={10}/> : <Clock size={10}/>}{status}
    </span>
  );
}

